    async def watch_order_book(self, symbol: str, limit: Int = None, params={}) -> OrderBook:
        """
        watches information on open orders with bid(buy) and ask(sell) prices, volumes and other data

        https://api.docs.extended.exchange/#order-book-stream

        :param str symbol: unified symbol of the market to fetch the order book for
        :param int [limit]: the maximum amount of order book entries to return
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.depth]: set to '1' to receive best bid and ask snapshots only
        :returns dict: A dictionary of `order book structures <https://docs.ccxt.com/?id=order-book-structure>`
        """
        await self.load_markets()
        market = self.market(symbol)
        symbol = market['symbol']
        messageHash = 'orderbook:' + symbol
        query = self.urlencode(params)
        url = self.urls['api']['ws'] + '/orderbooks/' + market['id']
        if len(query) > 0:
            url += '?' + query
        orderbook = await self.watch(url, messageHash, None, messageHash, {
            'symbol': symbol,
            'limit': limit,
        })
        return orderbook.limit()

    def handle_order_book(self, client: Client, message):
        #
        #     {
        #         "ts": 1701563440000,
        #         "type": "SNAPSHOT",
        #         "data": {
        #             "m": "BTC-USD",
        #             "b": [
        #                 {"p": "25670", "q": "0.1"}
        #             ],
        #             "a": [
        #                 {"p": "25770", "q": "0.1"}
        #             ]
        #         },
        #         "seq": 1
        #     }
        #
        data = self.safe_dict(message, 'data', {})
        marketId = self.safe_string(data, 'm')
        market = self.safe_market(marketId)
        symbol = market['symbol']
        messageHash = 'orderbook:' + symbol
        timestamp = self.safe_integer(message, 'ts')
        nonce = self.safe_integer(message, 'seq')
        type = self.safe_string(message, 'type', self.safe_string(data, 't'))
        if not (symbol in self.orderbooks):
            defaultLimit = self.safe_integer(self.options, 'watchOrderBookLimit', 1000)
            subscription = self.safe_dict(client.subscriptions, messageHash, {})
            limit = self.safe_integer(subscription, 'limit', defaultLimit)
            self.orderbooks[symbol] = self.order_book({}, limit)
        orderbook = self.orderbooks[symbol]
        if type == 'SNAPSHOT':
            snapshot = self.parse_order_book(data, symbol, timestamp, 'b', 'a', 'p', 'q')
            snapshot['nonce'] = nonce
            orderbook.reset(snapshot)
            client.resolve(orderbook, messageHash)
            return
        previousNonce = self.safe_integer(orderbook, 'nonce')
        if (previousNonce is not None) and (nonce != previousNonce + 1):
            del client.subscriptions[messageHash]
            del self.orderbooks[symbol]
            error = InvalidNonce(self.id + ' watchOrderBook received invalid nonce')
            client.reject(error, messageHash)
            return
        self.handle_deltas(orderbook['bids'], self.safe_list(data, 'b', []))
        self.handle_deltas(orderbook['asks'], self.safe_list(data, 'a', []))
        orderbook['timestamp'] = timestamp
        orderbook['datetime'] = self.iso8601(timestamp)
        orderbook['nonce'] = nonce
        client.resolve(orderbook, messageHash)

    def handle_delta(self, bookside, delta):
        price = self.safe_float(delta, 'p')
        amount = self.safe_float_2(delta, 'c', 'q')
        bookside.store(price, amount)

    def handle_deltas(self, bookside, deltas):
        for i in range(0, len(deltas)):
            self.handle_delta(bookside, deltas[i])

    async def watch_private(self, messageHash: str, subscription=None):
        self.check_required_credentials()
        url = self.urls['api']['ws'] + '/account'
        if (self.clients is None) or not (url in self.clients):
            defaultOptions = {
                'ws': {
                    'options': {
                        'headers': {},
                    },
                },
            }
            self.extend_exchange_options(defaultOptions)
            originalOptions = self.options['ws']['options']
            originalHeaders = self.safe_dict(originalOptions, 'headers', {})
            self.options['ws']['options'] = self.extend(self.extend({}, originalOptions), {
                'headers': self.extend(self.extend({
                    'User-Agent': self.userAgents['chrome'],
                }, originalHeaders), {
                    'X-Api-Key': self.apiKey,
                }),
            })
            self.client(url)
            self.options['ws']['options'] = originalOptions
        return await self.watch(url, messageHash, None, messageHash, subscription)

