    def handle_trades(self, client: Client, message):
        #
        #     {
        #         "ts": 1701563440000,
        #         "data": [
        #             {
        #                 "m": "BTC-USD",
        #                 "S": "BUY",
        #                 "tT": "TRADE",
        #                 "T": 1701563440000,
        #                 "p": "25670",
        #                 "q": "0.1",
        #                 "i": 25124
        #             }
        #         ],
        #         "seq": 2
        #     }
        #
        data = self.safe_list(message, 'data', [])
        first = self.safe_dict(data, 0)
        if first is None:
            return
        marketId = self.safe_string(first, 'm')
        market = self.safe_market(marketId)
        symbol = market['symbol']
        messageHash = 'trades:' + symbol
        subscription = self.safe_dict(client.subscriptions, messageHash, {})
        stored = self.safe_value(self.trades, symbol)
        if stored is None:
            defaultLimit = self.safe_integer(self.options, 'tradesLimit', 1000)
            limit = self.safe_integer(subscription, 'limit', defaultLimit)
            stored = ArrayCache(limit)
            self.trades[symbol] = stored
        previousNonce = self.safe_integer(subscription, 'nonce')
        nonce = self.safe_integer(message, 'seq')
        if (previousNonce is not None) and (nonce is not None) and (nonce <= previousNonce):
            return
        subscription['nonce'] = nonce
        for i in range(0, len(data)):
            trade = self.parse_trade(data[i], market)
            stored.append(trade)
        client.resolve(stored, messageHash)

    async def watch_ohlcv(self, symbol: str, timeframe='1m', since: Int = None, limit: Int = None, params={}) -> List[list]:
        """
        watches historical candlestick data containing the open, high, low, and close price, and the volume of a market

        https://api.docs.extended.exchange/#candles-stream

        :param str symbol: unified symbol of the market to fetch OHLCV data for
        :param str timeframe: the length of time each candle represents
        :param int [since]: timestamp in ms of the earliest candle to fetch
        :param int [limit]: the maximum amount of candles to fetch
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.candleType]: candle type: 'trades'(default), 'mark-prices', or 'index-prices'
        :param str [params.price]: *ignored if params.candleType is set* 'mark' or 'index' for mark price and index price candles
        :returns int[][]: A list of candles ordered, open, high, low, close, volume
        """
        await self.load_markets()
        market = self.market(symbol)
        symbol = market['symbol']
        price = self.safe_string(params, 'price')
        candleType = self.safe_string(params, 'candleType')
        if candleType is None:
            if price == 'mark':
                candleType = 'mark-prices'
            elif price == 'index':
                candleType = 'index-prices'
            else:
                candleType = 'trades'
        params = self.omit(params, ['candleType', 'price'])
        interval = self.safe_string(self.timeframes, timeframe, timeframe)
        messageHash = 'ohlcv:' + symbol + ':' + timeframe + ':' + candleType
        query = self.urlencode(self.extend({'interval': interval}, params))
        url = self.urls['api']['ws'] + '/candles/' + market['id'] + '/' + candleType + '?' + query
        ohlcv = await self.watch(url, messageHash, None, messageHash, {
            'name': 'ohlcv',
            'symbol': symbol,
            'timeframe': timeframe,
            'candleType': candleType,
            'limit': limit,
            'messageHash': messageHash,
        })
        if self.newUpdates:
            limit = ohlcv.getLimit(symbol, limit)
        return self.filter_by_since_limit(ohlcv, since, limit, 0, True)

    def handle_ohlcv(self, client: Client, message):
        #
        #     {
        #         "ts": 1695738675123,
        #         "data": [
        #             {
        #                 "T": 1695738674000,
        #                 "o": "1000.0000",
        #                 "l": "800.0000",
        #                 "h": "2400.0000",
        #                 "c": "2100.0000",
        #                 "v": "10.0000"
        #             }
        #         ],
        #         "seq": 1
        #     }
        #
        subscription = self.find_subscription(client, 'ohlcv')
        if subscription is None:
            return
        symbol = self.safe_string(subscription, 'symbol')
        timeframe = self.safe_string(subscription, 'timeframe')
        candleType = self.safe_string(subscription, 'candleType')
        cacheKey = timeframe if (candleType == 'trades') else timeframe + ':' + candleType
        messageHash = self.safe_string(subscription, 'messageHash')
        self.ohlcvs[symbol] = self.safe_value(self.ohlcvs, symbol, {})
        stored = self.safe_value(self.ohlcvs[symbol], cacheKey)
        if stored is None:
            defaultLimit = self.safe_integer(self.options, 'OHLCVLimit', 1000)
            limit = self.safe_integer(subscription, 'limit', defaultLimit)
            stored = ArrayCacheByTimestamp(limit)
            self.ohlcvs[symbol][cacheKey] = stored
        previousNonce = self.safe_integer(subscription, 'nonce')
        nonce = self.safe_integer(message, 'seq')
        if (previousNonce is not None) and (nonce is not None) and (nonce <= previousNonce):
            return
        subscription['nonce'] = nonce
        data = self.safe_list(message, 'data', [])
        for i in range(0, len(data)):
            parsed = self.parse_ohlcv(data[i])
            stored.append(parsed)
        client.resolve(stored, messageHash)

    def find_subscription(self, client: Client, name: str):
        keys = list(client.subscriptions.keys())
        for i in range(0, len(keys)):
            key = keys[i]
            subscription = self.safe_dict(client.subscriptions, key)
            subscriptionName = self.safe_string(subscription, 'name')
            if subscriptionName == name:
                return subscription
        return None

    def handle_error_message(self, client: Client, message) -> Bool:
        #
        #     {"status": "ERROR", "error": {"code": 1001, "message": "Market not found."}}
        #
        error = self.safe_value(message, 'error')
        if error is None:
            return False
        feedback = self.id + ' ' + self.json(message)
        errorCode = self.safe_string(error, 'code')
        self.throw_exactly_matched_exception(self.exceptions['exact'], errorCode, feedback)
        errorMessage = self.safe_string(error, 'message')
        self.throw_broadly_matched_exception(self.exceptions['broad'], errorMessage, feedback)
        raise ExchangeError(feedback)

    def handle_message(self, client: Client, message):
        if self.handle_error_message(client, message):
            return
        type = self.safe_string(message, 'type')
        data = self.safe_value(message, 'data')
        if isinstance(data, list):
            first = self.safe_dict(data, 0, {})
            side = self.safe_string(first, 'S')
            if side is not None:
                self.handle_trades(client, message)
            else:
                self.handle_ohlcv(client, message)
        elif data is not None:
            if (type == 'ORDER') or ('orders' in data):
                self.handle_orders(client, message)
            if (type == 'TRADE') or ('trades' in data):
                self.handle_my_trades(client, message)
            if (type == 'POSITION') or ('positions' in data):
                self.handle_positions(client, message)
            if (type == 'BALANCE') or ('balance' in data) or ('spotBalances' in data):
                self.handle_balance(client, message)
            if type == 'MP':
                self.handle_mark_price(client, message)
            elif 'f' in data:
                self.handle_funding_rate(client, message)
            else:
                self.handle_order_book(client, message)
